function solve(nums1) {
    let O_min = Infinity;
    let E_min = Infinity;
    let countOdd = 0;
    let countEven = 0;

    for (const x of nums1) {
        // Check parity: x % 2 === 1 for odd, x % 2 === 0 for even
        if (x % 2 !== 0) { // Odd
            countOdd++;
            if (x < O_min) {
                O_min = x;
            }
        } else { // Even
            countEven++;
            if (x < E_min) {
                E_min = x;
            }
        }
    }

    // Case 1: All numbers are the same parity (All Even or All Odd).
    // If all are even (O_min remains Infinity), we use option 1 (all even). -> True
    // If all are odd (E_min remains Infinity), we use option 1 (all odd). -> True
    if (countOdd === 0 || countEven === 0) {
        return true;
    }

    // Case 2: Mixed parities (countOdd >= 1 and countEven >= 1).
    // Target Even is impossible because the smallest odd number O_min cannot be transformed to even while maintaining positivity.
